  "use strict";

  var ALLOWED_MEDIA_LICENSES = { "CC0-1.0": 1, "PDM-1.0": 1, "CC-BY-4.0": 1, "CC-BY-SA-2.0": 1, "CC-BY-SA-2.5": 1, "CC-BY-SA-3.0": 1, "CC-BY-SA-4.0": 1 };

